def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r:*') as tar:
            def is_safe(member):
                if member.name.startswith('/') or '..' in member.name:
                    return None
                if member.issym():
                    return None
                return member

            tar.extractall(path=dest_path, filter=is_safe)
        return True
    except Exception:
        return False

