from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        tree = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    xpath_expr = "//student[username/text()=$username and password/text()=$password]"
    students = tree.xpath(xpath_expr, username=username, password=password)

    if not students:
        return None

    student = students[0]
    info = {}
    for child in student:
        info[child.tag] = child.text
    return info

