app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    user_input = request.args.get('code')
    if not user_input:
        return 'No code provided', 400
    try:
        # Compile the user input as an expression to limit execution scope
        code_obj = compile(user_input, '<string>', 'eval')
        # Use a restricted environment with minimal built-ins
        env = {'__builtins__': {}}
        result = eval(code_obj, env)
        return str(result)
    except Exception as e:
        return str(e), 500

